<script>
(()=>{'use strict';const api='api/pawn-customers.php',csrf=<?=json_encode($csrfToken)?>,id=<?=$pcId?>;function esc(v){return String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#039;','"':'&quot;'}[c]))}function money(v){return Number(v||0).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2})}function info(label,value){return `<div class="info-row"><div class="info-label">${label}</div><div class="info-value">${value||'-'}</div></div>`}function doc(path){if(!path)return'<span class="text-muted">Not uploaded</span>';if(path.toLowerCase().endsWith('.pdf'))return `<a target="_blank" href="${esc(path)}">Open PDF</a>`;return `<img class="preview" src="${esc(path)}">`}async function load(){const f=new FormData();f.append('action','view');f.append('pawn_customer_id',id);f.append('csrf_token',csrf);const r=await fetch(api,{method:'POST',body:f,credentials:'same-origin',headers:{Accept:'application/json'}}),raw=await r.text();let d;try{d=JSON.parse(raw)}catch(e){return alert(raw.slice(0,300))}if(!r.ok||!d.success)return alert(d.message||'Unable to load');const c=d.customer,s=d.summary;sub.textContent=c.customer_name+' - '+c.customer_code;vLoans.textContent=s.total_loans;vActive.textContent=s.active_loans;vAmount.textContent='₹'+money(s.total_principal);vOutstanding.textContent='₹'+money(s.total_outstanding);personal.innerHTML=info('Name',esc(c.customer_name))+info('Guardian',esc(c.guardian_name))+info('DOB',esc(c.date_of_birth_display))+info('Mobile',esc(c.mobile))+info('Alternate Mobile',esc(c.alternate_mobile))+info('Email',esc(c.email))+info('Address',esc([c.address_line1,c.address_line2,c.city,c.state,c.pincode].filter(Boolean).join(', ')));profile.innerHTML=info('Occupation',esc(c.occupation))+info('Annual Income','₹'+money(c.annual_income))+info('Credit Limit','₹'+money(c.credit_limit))+info('Risk',esc(c.risk_category))+info('KYC',Number(c.kyc_verified)===1?'Verified':'Pending')+info('Reference',esc(c.reference_name)+' '+esc(c.reference_mobile))+info('Notes',esc(c.notes));photo.innerHTML=doc(c.photo_path);signature.innerHTML=doc(c.signature_path);kycDoc.innerHTML=doc(c.kyc_document_path);loansBody.innerHTML=d.loans.length?d.loans.map(x=>`<tr><td>${esc(x.pawn_no)}</td><td>${esc(x.pawn_date_display)}</td><td>${esc(x.category_name)}</td><td>₹${money(x.principal_amount)}</td><td>₹${money(x.balance_principal)}</td><td>${Number(x.interest_percent).toFixed(3)}% ${esc(x.interest_period)}</td><td>${esc(x.status)}</td><td><a href="pawn-view.php?id=${x.id}" class="btn-soft py-1 px-2">View</a></td></tr>`).join(''):'<tr><td colspan="8" class="text-center">No loans</td></tr>';paymentsBody.innerHTML=d.payments.length?d.payments.map(x=>`<tr><td>${esc(x.payment_date_display)}</td><td>${esc(x.pawn_no)}</td><td>${esc(x.receipt_no)}</td><td>₹${money(x.total_amount)}</td></tr>`).join(''):'<tr><td colspan="4" class="text-center">No payments</td></tr>';interestBody.innerHTML=d.interests.length?d.interests.map(x=>`<tr><td>${esc(x.collection_date_display)}</td><td>${esc(x.pawn_no)}</td><td>${esc(x.receipt_no)}</td><td>₹${money(x.total_amount)}</td></tr>`).join(''):'<tr><td colspan="4" class="text-center">No collections</td></tr>';loading.classList.remove('show');content.style.display=''}load()})();
</script></body></html>